import json
import uuid
from dataclasses import dataclass, field, asdict
from datetime import datetime, UTC
from pathlib import Path
from typing import Any

@dataclass
class AgentSnapshot:
    snapshot_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    agent_id: str = ""
    created_at: str = field(default_factory=lambda: datetime.now(UTC).isoformat())
    iteration: int = 0
    messages: list[dict] = field(default_factory=list)
    tool_results_pending: list[dict] = field(default_factory=list)
    work_queue: list[Any] = field(default_factory=list)
    session_approved: list[str] = field(default_factory=list)  # set → list for JSON
    metadata: dict = field(default_factory=dict)   # caller-provided extras

    def to_json(self) -> str:
        return json.dumps(asdict(self), ensure_ascii=False, indent=2)

    @classmethod
    def from_json(cls, raw: str) -> "AgentSnapshot":
        data = json.loads(raw)
        return cls(**data)

import zlib

def compress_messages(messages: list[dict]) -> bytes:
    raw = json.dumps(messages, ensure_ascii=False).encode()
    return zlib.compress(raw, level=6)

def decompress_messages(data: bytes) -> list[dict]:
    return json.loads(zlib.decompress(data).decode())

SNAPSHOT_VERSION = 2

@dataclass
class AgentSnapshot:
    version: int = SNAPSHOT_VERSION
    # ... other fields ...

    @classmethod
    def from_json(cls, raw: str) -> "AgentSnapshot":
        data = json.loads(raw)
        data = _migrate(data)
        return cls(**data)

def _migrate(data: dict) -> dict:
    version = data.get("version", 1)
    if version < 2:
        # v1 → v2: session_approved was a list of tool names; now list of "tool:actor" strings
        data["session_approved"] = [
            f"{s}:unknown" for s in data.get("session_approved", [])
        ]
        data["version"] = 2
    return data

from fastapi import FastAPI, HTTPException

app = FastAPI()
store = FileCheckpointStore()

@app.get("/agents/{agent_id}/checkpoints")
async def list_checkpoints(agent_id: str):
    ids = await store.list_for_agent(agent_id)
    return {"agent_id": agent_id, "checkpoints": ids}

@app.get("/agents/{agent_id}/checkpoints/{snapshot_id}")
async def get_checkpoint(agent_id: str, snapshot_id: str):
    snap = await store.load(snapshot_id)
    if not snap or snap.agent_id != agent_id:
        raise HTTPException(404, "Checkpoint not found")
    return {
        "snapshot_id": snap.snapshot_id,
        "created_at": snap.created_at,
        "iteration": snap.iteration,
        "message_count": len(snap.messages),
        "queue_length": len(snap.work_queue),
    }

@app.delete("/agents/{agent_id}/checkpoints/{snapshot_id}")
async def delete_checkpoint(agent_id: str, snapshot_id: str):
    snap = await store.load(snapshot_id)
    if not snap or snap.agent_id != agent_id:
        raise HTTPException(404, "Checkpoint not found")
    await store.delete(snapshot_id)
    return {"deleted": snapshot_id}

@app.post("/agents/{agent_id}/resume/{snapshot_id}")
async def resume_agent(agent_id: str, snapshot_id: str):
    snap = await store.load(snapshot_id)
    if not snap or snap.agent_id != agent_id:
        raise HTTPException(404, "Checkpoint not found")
    # Launch resume as a background task
    asyncio.create_task(
        run_with_checkpointing(
            agent_id=agent_id,
            system=_get_system_prompt(agent_id),
            messages=[],
            tools=MY_TOOLS,
            store=store,
            pause_token=asyncio.Event(),
            resume_from=snapshot_id,
        )
    )
    return {"status": "resuming", "from_snapshot": snapshot_id, "iteration": snap.iteration}
